int num_pipes_spawned = 0;

double jump_strength = 0;
int bird_x = 50;
int bird_y = 100;

int prev_bird_x = 50;
int prev_bird_y = 100;

bool game_over = false;

// function declarations
void wait_for_vsync();
bool timer_done();
void plot_pixel(int x, int y, short int color);
void clear_screen();
void draw_bird(int x, int y);
void erase_bird(int x, int y);
void detect_collision(int pipe);

int main(void)
{

    srand(time(NULL));

    // clear timeout bit
    *timer_status = 0;

    // load start value
    *timer_periodl = PIPE_SPAWN_INTERVAL_LOW;
    *timer_periodh = PIPE_SPAWN_INTERVAL_HIGH;

    // START = bit 2, CONT = bit 1
    *timer_control = (1 << 2) | (1 << 1);

    // set front buffer
    *(pixel_ctrl_ptr + 1) = (int)&Buffer1;
    wait_for_vsync();
    pixel_buffer_start = *pixel_ctrl_ptr;
    clear_screen();

    // set back buffer
    *(pixel_ctrl_ptr + 1) = (int)&Buffer2;
    pixel_buffer_start = *(pixel_ctrl_ptr + 1);
    clear_screen();
    
    spawn_pipe();

    while(!game_over)
    {
        
        // update positions
        for(int i = 0; i < num_pipes_spawned; i++){
            pipe_pos[i][0]--;
        }

        if (timer_done()){
            spawn_pipe();
        }
        
        //draw_pipe();

        // erase old bird
        //erase_bird(prev_bird_x, prev_bird_y);
        draw_pipe();
        
        bird_velocity = jump_strength;
        // apply gravity
        bird_velocity += GRAVITY;
        bird_y += bird_velocity;

        // bounds (so it doesn't fly off screen)
        if (bird_y < 0) {
            bird_y = 0;
            bird_velocity = 0;
        }

        if (bird_y > SCREEN_HEIGHT - BIRD_HEIGHT) {
            bird_y = SCREEN_HEIGHT - BIRD_HEIGHT;
            bird_velocity = 0;
        }

        //draw new bird :p

        erase_bird(prev_bird_x, prev_bird_y);
        draw_bird(bird_x, bird_y);

        wait_for_vsync();
        pixel_buffer_start = *(pixel_ctrl_ptr + 1);
        erase_bird(prev_bird_x, prev_bird_y);
        draw_bird(bird_x, bird_y);
         // update previous position
        prev_bird_x = bird_x;
        prev_bird_y = bird_y;
        draw_pipe();
    }
}

bool timer_done() {
    if ((*timer_status) & 1) {
        *timer_status = 0;   // clear TO
        return true;
    }
    return false;
}

void spawn_pipe()
{   
    //randomize top and bottom pipes
    int pipe_spawn_y = (rand() % 2) ? 0 : SCREEN_HEIGHT;

    // pick a random pipe height between PIPE_MIN_HEIGHT and PIPE_MAX_HEIGHT
    int pipe_height = (rand() % (PIPE_MAX_HEIGHT - PIPE_MIN_HEIGHT + 1)) + PIPE_MIN_HEIGHT;

    //if pipe is at the top draw downward, otherwise draw updward
    int y_dir = pipe_spawn_y == 0 ? 1 : -1;

    pipe_pos[next_pipe_index][0] = SCREEN_WIDTH;
    pipe_pos[next_pipe_index][1] = pipe_spawn_y;
    pipe_pos[next_pipe_index][2] = pipe_height;

    if (num_pipes_spawned < MAX_PIPES) {
        num_pipes_spawned++;
    }

    next_pipe_index = (next_pipe_index + 1) % MAX_PIPES;

    draw_pipe();
}

void draw_pipe(){
    // iterate through all pipes and draw them
    for (int pipe = 0 ; pipe < num_pipes_spawned ; pipe++){
        int y_dir = pipe_pos[pipe][1] == 0 ? 1 : -1;

        for(int i = 0; i < pipe_pos[pipe][2]; i++){
            // draw next line of pipe
            //pipe_pos[pipe][0] = starting x pos
            //pipe_pos[pipe][1] = starting y pos
            //pipe_pos[pipe][2] = pipe length
            plot_pixel(pipe_pos[pipe][0], pipe_pos[pipe][1] + i*y_dir, PIPE_COLOUR);
            // erase previous line of pipe
            plot_pixel(pipe_pos[pipe][0] + PIPE_WIDTH, pipe_pos[pipe][1] + i*y_dir, BG[(pipe_pos[pipe][1] + i*y_dir) * BG_WIDTH + pipe_pos[pipe][0] + PIPE_WIDTH-1]);
            // if pipe is within x range of the bird check for collision
            if ((pipe_pos[pipe][0] + PIPE_WIDTH) >  bird_x && pipe_pos[pipe][0] < (bird_x + BIRD_WIDTH)){
                check_collision(pipe);
            }
        }
    }
}

void clear_screen (){
    for (int x = 0 ; x < 320 ; x++){
        for (int y = 0 ; y < 240 ; y++){
            plot_pixel(x, y, BG[BG_WIDTH * y + x]);
        }
    }
}

void plot_pixel(int x, int y, short int color)
{
    if (x < 0 || x > SCREEN_WIDTH || y < 0 || y > SCREEN_HEIGHT)
        return;

    volatile short int *one_pixel_address;

    one_pixel_address = (short int *)(pixel_buffer_start + (y << 10) + (x << 1));
    *one_pixel_address = color;
}

void wait_for_vsync()
{
    volatile int * pixel_ctrl_ptr = (int *)0xFF203020;
    int status;

    *pixel_ctrl_ptr = 1;

    status = *(pixel_ctrl_ptr + 3);
    while((status & 0x01) != 0)
        status = *(pixel_ctrl_ptr + 3);
}

void draw_bird(int x, int y)
{
    for (int row = 0; row < BIRD_HEIGHT; row++) {
        for (int col = 0; col < BIRD_WIDTH; col++) {

            short color = BIRD[row * BIRD_WIDTH + col];

            // skip black pixels (transparent)
            if (color != 0x0000) {
                plot_pixel(x + col, y + row, color);
            }
        }
    }
}

void erase_bird(int x, int y)
{
    for (int row = 0; row < BIRD_HEIGHT; row++) {
        for (int col = 0; col < BIRD_WIDTH; col++) {

            int draw_x = x + col;
            int draw_y = y + row;

            if (draw_x >= 0 && draw_x < SCREEN_WIDTH &&
                draw_y >= 0 && draw_y < SCREEN_HEIGHT) {

                plot_pixel(draw_x, draw_y,
                    BG[draw_y * BG_WIDTH + draw_x]);
            }
        }
    }
}

