void detect_collision(int pipe){
    //top pipe collision check
    if (pipe_pos[pipe][1] == 0 && pipe_pos[pipe][2] >= bird_y){
        game_over = true;
        return;
    } 
    //bottom pipe collision check
    else if (pipe_pos[pipe][2] <= (bird_y + BIRD_HEIGHT)){
        game_over = true;
        return;
    }
}